    // Check if the must_edges form a connected graph
    // If not, return -1
    vector<bool> visited(n, false);
    vector<vector<pair<long long, long long>>> adj(n);

    for (auto& edge : must_edges) {
        adj[edge[0]].push_back({edge[1], edge[2]});
        adj[edge[1]].push_back({edge[0], edge[2]});
    }

    queue<long long> q;
    q.push(0);
    visited[0] = true;

    while (!q.empty()) {
        long long u = q.front();
        q.pop();
        for (auto& [v, _] : adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                q.push(v);
            }
        }
    }

    for (long long i = 1; i < n; ++i) {
        if (!visited[i]) {
            return -1;
        }
    }

    // Use a priority queue to find the maximum possible minimum strength
    // We will try different possible minimum strengths and check if it's possible to form a spanning tree
    // We sort the optional edges by their strength and try to include the strongest ones first

    // Sort optional edges by strength
    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    // Use a max-heap to find the maximum possible minimum strength
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;

    // Initialize the priority queue with must_edges
    for (auto& edge : must_edges) {
        pq.push({edge[2], edge[0]});
        pq.push({edge[2], edge[1]});
    }

    // Use a union-find data structure to check connectivity
    vector<long long> parent(n, -1);

    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    auto union_set = [&](long long x, long long y) -> bool {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return false;
        }
        parent[root_y] = root_x;
        return true;
    };

    // Add must_edges to the union-find structure
    for (auto& edge : must_edges) {
        union_set(edge[0], edge[1]);
    }

    // Try to include optional edges with upgrades
    long long used_upgrades = 0;
    long long min_strength = 0;

    for (auto& edge : optional_edges) {
        // Try to use this edge with an upgrade
        if (used_upgrades < k) {
            long long new_strength = edge[2] * 2;
            // Add this edge to the union-find structure
            if (union_set(edge[0], edge[1])) {
                // If it connects two components, it's a good candidate for the spanning tree
                // We can consider this as part of the spanning tree
                // Update the min_strength
                min_strength = min(min_strength, new_strength);
                used_upgrades++;
            }
        } else {
            // No more upgrades left, just add the original strength
            if (union_set(edge[0], edge[1])) {
                min_strength = min(min_strength, edge[2]);
            }
        }
    }

    // Check if all nodes are connected
    long long root = find(0);
    for (long long i = 1; i < n; ++i) {
        if (find(i) != root) {
            return -1;
        }
    }

    return min_strength;
